);

const params = {
    "per_page": "20",
    "status": "open",
    "filter[user_id]": "01HZY1K8QK8ZQ2V6J8F4K8Q2V6",
    "filter[subject]": "Issue with ride",
    "sort": "-created_at",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
