<span id="example-requests-PUTapi-v1-admin-promo-codes--promoCode_id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://localhost:8080/api/v1/admin/promo-codes/architecto" \
    --header "Authorization: Bearer &amp;lt;token&amp;gt;" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"code\": \"SUMMER2024\",
    \"title\": \"Summer Discount\",
    \"description\": \"Get 20% off your summer rides!\",
    \"discount_type\": \"percentage\",
    \"discount_value\": 20,
    \"max_discount_amount\": 100,
    \"min_order_amount\": 50,
    \"usage_limit\": 1000,
    \"usage_limit_per_user\": 1,
    \"starts_at\": \"2024-06-01 00:00:00\",
    \"expires_at\": \"2024-08-31 23:59:59\",
    \"is_active\": true
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8080/api/v1/admin/promo-codes/architecto"
);

const headers = {
    "Authorization": "Bearer &amp;lt;token&amp;gt;",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "code": "SUMMER2024",
    "title": "Summer Discount",
    "description": "Get 20% off your summer rides!",
    "discount_type": "percentage",
    "discount_value": 20,
    "max_discount_amount": 100,
    "min_order_amount": 50,
    "usage_limit": 1000,
    "usage_limit_per_user": 1,
    "starts_at": "2024-06-01 00:00:00",
    "expires_at": "2024-08-31 23:59:59",
    "is_active": true
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>


