            'Authorization' =&gt; 'Bearer &lt;token&gt;',
            'Content-Type' =&gt; 'multipart/form-data',
            'Accept' =&gt; 'application/json',
        ],
        'multipart' =&gt; [
            [
                'name' =&gt; 'avatar',
                'contents' =&gt; fopen('/tmp/php3qa1erl457mo4dcfJCj', 'r')
            ],
        ],
    ]
);
$body = $response-&gt;getBody();
