                <h1 id="support">Support</h1>

    

                                <h2 id="support-GETapi-v1-support-tickets">Get Tickets</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Get list of user's support tickets</p>

<span id="example-requests-GETapi-v1-support-tickets">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost:8080/api/v1/support/tickets?per_page=15&amp;filter[status]=architecto&amp;filter[subject]=n&amp;sort=-created_at" \
    --header "Authorization: Bearer &amp;lt;token&amp;gt;" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8080/api/v1/support/tickets"
);

const params = {
    "per_page": "15",
    "filter[status]": "architecto",
    "filter[subject]": "n",
    "sort": "-created_at",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer &amp;lt;token&amp;gt;",
    "Content-Type": "application/json",
    "Accept": "application/json",
};


fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>


<div class="php-example">
    <pre><code class="language-php">$client = new \GuzzleHttp\Client();
$url = 'http://localhost:8080/api/v1/support/tickets';
$response = $client-&gt;get(
    $url,
    [
        'headers' =&gt; [
            'Authorization' =&gt; 'Bearer &lt;token&gt;',
            'Content-Type' =&gt; 'application/json',
            'Accept' =&gt; 'application/json',
        ],
        'query' =&gt; [
            'per_page' =&gt; '15',
            'filter[status]' =&gt; 'architecto',
            'filter[subject]' =&gt; 'n',
            'sort' =&gt; '-created_at',
        ],
    ]
);
$body = $response-&gt;getBody();
print_r(json_decode((string) $body));</code></pre></div>


